//  Generated by Admin Panel · gna-owner-panel.html
//  HOW TO USE:
//    1. Open Admin Panel → go to Products page
//    2. Click "⬇️ Export Products" or "⬇️ Update Website Files"
//    3. Replace this file with the downloaded gna-products-data.js
//    4. Re-upload to your website host — products appear instantly!
// ══════════════════════════════════════════════════════════════

// ── PRODUCT DATA (populated by admin export) ──
var GNA_PRODUCTS_DATA = [];

// ── AUTO-SEED: merges exported data into localStorage ──
(function () {
  try {
    if (GNA_PRODUCTS_DATA && GNA_PRODUCTS_DATA.length > 0) {
      var existing = [];
      try { existing = JSON.parse(localStorage.getItem('gna_products') || '[]'); } catch (e) {}
      var merged = existing.slice();
      GNA_PRODUCTS_DATA.forEach(function (p) {
        var idx = -1;
        for (var i = 0; i < merged.length; i++) { if (merged[i].id === p.id) { idx = i; break; } }
        if (idx >= 0) merged[idx] = p;
        else merged.push(p);
      });
      localStorage.setItem('gna_products', JSON.stringify(merged));
      console.log('[GnA] ' + merged.length + ' products seeded to storage.');
    }
  } catch (e) {
    console.warn('[GnA] Could not seed product data:', e);
  }
})();
